	@Test
	public void sharesOneLazySessionAcrossIslandsAndRebuildsOnceAfterLegacyMutation() throws Exception {
		QueryRoot consecutiveRoot = new QueryRoot(new SingletonSet());
		RecordingOptimizer first = new RecordingOptimizer();
		RecordingOptimizer second = new RecordingOptimizer();
		run(consecutiveRoot, List.of(first, second), ScopeSafetyMode.ENFORCE);
		assertThat(first.sessions).containsExactlyElementsOf(second.sessions);
		assertThat(first.analyses.get(0)).isSameAs(second.analyses.get(0));

		QueryRoot invalidatedRoot = new QueryRoot(new SingletonSet());
		RecordingOptimizer beforeLegacy = new RecordingOptimizer();
		RecordingOptimizer afterLegacy = new RecordingOptimizer();
		QueryOptimizer legacy = (tupleExpr, dataset, bindings) -> {
			// Deliberately no tree edit: legacy identity alone invalidates facts.
		};
		run(invalidatedRoot, List.of(beforeLegacy, legacy, afterLegacy), ScopeSafetyMode.ENFORCE);
		assertThat(beforeLegacy.sessions.get(0)).isSameAs(afterLegacy.sessions.get(0));
		assertThat(beforeLegacy.analyses.get(0)).isNotSameAs(afterLegacy.analyses.get(0));
	}

	@Test
	public void offRunsTheLegacyCompatibleEntryWithoutConstructingFacts() throws Exception {
		QueryRoot root = new QueryRoot(new SingletonSet());
		RecordingOptimizer optimizer = new RecordingOptimizer();
		run(root, List.of(optimizer), ScopeSafetyMode.OFF);
		assertThat(optimizer.sessions).hasSize(1);
		assertThat(optimizer.analyses).isEmpty();
		assertThat(root.getOptimizationTag()).isZero();
	}

