	private static final class RecordingOptimizer implements ContextAwareQueryOptimizer {

		private final List<OptimizationSession> sessions = new ArrayList<>();
		private final List<ScopeAnalysis> analyses = new ArrayList<>();

		@Override
		public void optimize(TupleExpr tupleExpr, Dataset dataset, BindingSet bindings,
				OptimizationSession session) {
			sessions.add(session);
			if (session.mode() != ScopeSafetyMode.OFF) {
				analyses.add(session.analysis());
			}
		}
	}
